$(function(){"use strict";var a;$("#searchStudentInput").on("keyup",function(){clearTimeout(a),a=setTimeout(function(){var a=$("#searchStudentInput").val(),t=$("#searchStudentInput").data("url"),e=$("#searchStudentInput").data("profile-url");if(a.trim()){var n=t+"/"+a;console.log("Search URL:",n),$.ajax({url:n,method:"GET",beforeSend:function(){$(".offcanvas-body").html("<p>Loading...</p>")},success:function(a){if(a.success&&a.data.data.length>0){var t="";$.each(a.data.data,function(a,n){var c;t+='\n                <div class="card my-2" style="border-color: rgb(136,211,202);">\n                  <div class="card-body d-flex p-1">\n                    <div class="px-1 text-dark">'.concat(n.student.access_number||"N/A",'</div>\n                    <div class="px-1 text-uppercase fw-bold text-dark"><a href="').concat(e.replace("replace",n.student.uuid),'">').concat(n.student.first_name," ").concat(n.student.last_name,'</a></div>\n                    <div class="px-1 text-capitalize"> ').concat((null===(c=n.student.course)||void 0===c?void 0:c.name)||"N/A","</div>\n                  </div>\n                </div>\n              ")}),$(".offcanvas-body").html(t)}else $(".offcanvas-body").html("<p>No students found matching your search criteria.</p>")},error:function(){$(".offcanvas-body").html("<p>An error occurred while searching. Please try again later.</p>")}})}else $(".offcanvas-body").html("<p>Please enter a search term.</p>")},500)})});